def rainwater_v1(height):
    if len(height) < 2:
        return 0
    start = height.index(max(height))
    rotated = height[start:] + height[:start]
    left = 0
    right = len(rotated) - 1
    left_max = 0
    right_max = 0
    total = 0
    while left < right:
        if rotated[left] <= rotated[right]:
            if rotated[left] >= left_max:
                left_max = rotated[left]
            else:
                total += left_max - rotated[left]
            left += 1
        else:
            if rotated[right] >= right_max:
                right_max = rotated[right]
            else:
                total += right_max - rotated[right]
            right -= 1
    return total

def binary_search_rank(nums, target):
    count = 0
    prev = None
    seen = False
    for value in nums:
        if not seen or value != prev:
            if value <= target:
                count += 1
            else:
                break
            prev = value
            seen = True
    return count

def two_sum_all_1based(nums, target):
    pairs = []
    for i in range(len(nums)):
        for j in range(i + 1, len(nums)):
            if nums[i] + nums[j] == target:
                pairs.append([i + 1, j + 1])
    return pairs

def merge_half_open_strict(intervals):
    normalized = []
    for start, end in intervals:
        if start > end:
            start, end = end, start
        if start != end:
            normalized.append([start, end])
    normalized.sort()
    merged = []
    for start, end in normalized:
        if not merged or start >= merged[-1][1]:
            merged.append([start, end])
        else:
            if end > merged[-1][1]:
                merged[-1][1] = end
    return merged

def valid_parens_escape(s):
    stack = []
    pairs = {')': '(', ']': '[', '}': '{'}
    opens = set(pairs.values())
    i = 0
    while i < len(s):
        ch = s[i]
        if ch == '\\':
            i += 2
            continue
        if ch in opens:
            stack.append(ch)
        elif ch in pairs:
            if not stack or stack[-1] != pairs[ch]:
                return False
            stack.pop()
        i += 1
    return not stack
